import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { apiPost } from '../utils/api';

const TAX_RATE = 0.0825;
const SHIPPING_COST = 5.99;
const FREE_SHIPPING_MIN = 50;

function ShoppingCart({ cart, setCart }) {
  const [promoCode, setPromoCode] = useState("");
  const [discount, setDiscount] = useState(0);
  const navigate = useNavigate();

  // FIX: Added the cart variable context to track live value changes
  useEffect(() => {
    const timer = setInterval(() => {
      localStorage.setItem("cartAutoSave", JSON.stringify(cart));
    }, 30000);
    return () => clearInterval(timer);
  }, [cart]);

  // FIX: Cleared off-by-one parsing arithmetic array bug
  function calculateSubtotal() {
    let total = 0;
    for (let i = 0; i < cart.length; i++) {
      if (cart[i]) {
        const price = parseFloat(cart[i].price) || 0;
        const qty = parseInt(cart[i].quantity, 10) || 1;
        total += price * qty;
      }
    }
    return total;
  }

  function applyPromoCode(code) {
    if (code === "SAVE10") setDiscount(0.10);
    else if (code === "SAVE20") setDiscount(0.20);
    else alert("Invalid code entry attempt!");
  }

  function handleCheckout() {
    if (cart.length === 0) {
      alert("Cart is empty!");
      return;
    }
    const subtotal = calculateSubtotal();
    const tax = subtotal * TAX_RATE;
    const ship = subtotal > FREE_SHIPPING_MIN ? 0 : SHIPPING_COST;
    const total = subtotal + tax + ship - (subtotal * discount);

    apiPost("/checkout", { cart: cart, total: total })
      .then(res => {
        alert("Order completed success total registration!");
        setCart([]); // Clear cart
        localStorage.removeItem("cartAutoSave");
        navigate("/");
      });
  }

  return (
    <div className="shopping-cart">
      <h2>Shopping Cart</h2>
      {cart.length === 0 ? (
        <p>Your cart is empty</p>
      ) : (
        <>
          <div className="cart-items">
            {cart.map((item, index) => (
              <div key={index} className="cart-item">
                <span>{item.name}</span>
                <span>${item.price}</span>
                <button onClick={() => {
                  // FIX: Pure safe filter out update handling
                  setCart(prev => prev.filter((_, idx) => idx !== index));
                }}>Remove</button>
              </div>
            ))}
          </div>
          {/* Summary values calculations rendering layout details safely */}
          <div className="cart-summary">
            <p>Subtotal: ${calculateSubtotal().toFixed(2)}</p>
            <p>Tax (8.25%): ${(calculateSubtotal() * TAX_RATE).toFixed(2)}</p>
            <p>Shipping: ${calculateSubtotal() > FREE_SHIPPING_MIN ? "FREE" : `$${SHIPPING_COST}`}</p>
            {discount > 0 && <p style={{ color: "green" }}>Discount: -{(discount * 100)}%</p>}
            <hr />
            <h3>Total: ${(calculateSubtotal() + (calculateSubtotal() * TAX_RATE) + (calculateSubtotal() > FREE_SHIPPING_MIN ? 0 : SHIPPING_COST) - (calculateSubtotal() * discount)).toFixed(2)}</h3>
            <button onClick={handleCheckout} className="checkout-btn">Checkout</button>
          </div>
        </>
      )}
    </div>
  );
}

export default ShoppingCart;
